class Solution {
    public String licenseKeyFormatting(String s, int k) {
        StringBuilder sb = new StringBuilder();
        int count = 0;
        for (int i = s.length() - 1; i >= 0; i--) {
            if (s.charAt(i) == '-') {
                continue;
            }
            if (count == k) {
                sb.insert(0, '-');
                count = 0;
            }
            sb.insert(0, Character.toUpperCase(s.charAt(i)));
            count++;
        }
        return sb.toString();
    }
}
